import React, { useState, useCallback } from 'react';
import Window from './Window';
import Taskbar from './Taskbar';
import DesktopIcon from './DesktopIcon';
import Home from '../pages/Home';
import About from '../pages/About';
import Experience from '../pages/Experience';
import Skills from '../pages/Skills';
import Contact from '../pages/Contact';

type PageKey = 'home' | 'about' | 'experience' | 'skills' | 'contact';

interface WindowState {
  id: string;
  title: string;
  page: PageKey;
  minimized: boolean;
  zIndex: number;
}

let zCounter = 10;

const PAGE_TITLES: Record<PageKey, string> = {
  home: 'Raghv Bhatia â€” Portfolio',
  about: 'About Me',
  experience: 'Work Experience',
  skills: 'Skills & Certifications',
  contact: 'Contact',
};

const Desktop: React.FC = () => {
  const [windows, setWindows] = useState<WindowState[]>([
    { id: 'portfolio', title: 'Raghv Bhatia â€” Portfolio', page: 'home', minimized: false, zIndex: 10 }
  ]);
  const [activePage, setActivePage] = useState<Record<string, PageKey>>({ portfolio: 'home' });

  const openWindow = useCallback((page: PageKey) => {
    const existing = windows.find(w => w.page === page || (page === 'home' && w.id === 'portfolio'));
    if (existing) {
      setWindows(prev => prev.map(w =>
        w.id === existing.id ? { ...w, minimized: false, zIndex: ++zCounter } : w
      ));
      return;
    }
    const id = `${page}-${Date.now()}`;
    setWindows(prev => [...prev, {
      id, title: PAGE_TITLES[page], page, minimized: false, zIndex: ++zCounter
    }]);
    setActivePage(prev => ({ ...prev, [id]: page }));
  }, [windows]);

  const closeWindow = useCallback((id: string) => {
    setWindows(prev => prev.filter(w => w.id !== id));
  }, []);

  const focusWindow = useCallback((id: string) => {
    setWindows(prev => prev.map(w =>
      w.id === id ? { ...w, zIndex: ++zCounter, minimized: false } : w
    ));
  }, []);

  const toggleMinimize = useCallback((id: string) => {
    setWindows(prev => prev.map(w =>
      w.id === id ? { ...w, minimized: !w.minimized } : w
    ));
  }, []);

  const navigate = useCallback((winId: string, page: PageKey) => {
    setActivePage(prev => ({ ...prev, [winId]: page }));
  }, []);

  const activeId = [...windows].sort((a, b) => b.zIndex - a.zIndex)[0]?.id ?? '';

  const renderPage = (winId: string, page: PageKey) => {
    const nav = (p: PageKey) => navigate(winId, p);
    switch (page) {
      case 'home': return <Home navigate={nav} />;
      case 'about': return <About />;
      case 'experience': return <Experience />;
      case 'skills': return <Skills />;
      case 'contact': return <Contact />;
    }
  };

  const desktopIcons = [
    { label: 'My Portfolio', icon: 'đź–Ąď¸Ź', page: 'home' as PageKey },
    { label: 'About Me', icon: 'đź‘¤', page: 'about' as PageKey },
    { label: 'Experience', icon: 'đź’Ľ', page: 'experience' as PageKey },
    { label: 'Skills', icon: 'đźŽ“', page: 'skills' as PageKey },
    { label: 'Contact', icon: 'âś‰ď¸Ź', page: 'contact' as PageKey },
  ];

  return (
    <div style={{ width: '100vw', height: '100vh', background: '#008080', position: 'relative', overflow: 'hidden' }}>

      {/* Desktop Icons */}
      <div style={{ position: 'absolute', top: 16, left: 16, display: 'flex', flexDirection: 'column', zIndex: 1 }}>
        {desktopIcons.map(icon => (
          <DesktopIcon
            key={icon.page}
            label={icon.label}
            icon={icon.icon}
            onClick={() => openWindow(icon.page)}
          />
        ))}
      </div>

      {/* Windows */}
      {windows.map(w => !w.minimized && (
        <Window
          key={w.id}
          title={PAGE_TITLES[activePage[w.id] ?? w.page]}
          onClose={() => closeWindow(w.id)}
          onMinimize={() => toggleMinimize(w.id)}
          onFocus={() => focusWindow(w.id)}
          zIndex={w.zIndex}
          initialX={w.id === 'portfolio' ? 80 : 120}
          initialY={w.id === 'portfolio' ? 20 : 40}
          initialWidth={800}
          initialHeight={520}
        >
          {/* Sidebar nav */}
          <div style={{ display: 'flex', height: '100%' }}>
            <div style={{
              width: 150,
              background: '#f0f0f0',
              borderRight: '1px solid #c0c0c0',
              flexShrink: 0,
              display: 'flex',
              flexDirection: 'column',
              padding: '16px 0',
            }}>
              <div style={{ padding: '0 12px', marginBottom: 16 }}>
                <div style={{ fontSize: 13, fontWeight: 'bold', color: '#000080' }}>Raghv</div>
                <div style={{ fontSize: 11, color: '#555' }}>Bhatia</div>
              </div>
              {(['home','about','experience','skills','contact'] as PageKey[]).map(p => {
                const current = activePage[w.id] ?? w.page;
                return (
                  <div
                    key={p}
                    onClick={() => navigate(w.id, p)}
                    style={{
                      padding: '7px 14px',
                      cursor: 'pointer',
                      fontSize: 11,
                      background: current === p ? '#000080' : 'transparent',
                      color: current === p ? '#fff' : '#000',
                      fontWeight: current === p ? 'bold' : 'normal',
                    }}
                  >
                    {PAGE_TITLES[p].split('â€”').pop()?.trim() ?? PAGE_TITLES[p]}
                  </div>
                );
              })}
            </div>
            {/* Main content */}
            <div style={{ flex: 1, overflow: 'auto' }}>
              {renderPage(w.id, activePage[w.id] ?? w.page)}
            </div>
          </div>
        </Window>
      ))}

      {/* Taskbar */}
      <Taskbar
        windows={windows.map(w => ({ id: w.id, title: PAGE_TITLES[activePage[w.id] ?? w.page], minimized: w.minimized }))}
        onToggle={toggleMinimize}
        activeId={activeId}
      />
    </div>
  );
};

export default Desktop;
